/**
 * WorldGenerator — Procedural world generation for Spellroads.
 * Produces a complete worldData object from a params set.
 * All randomness is seeded and deterministic.
 *
 * @module WorldGenerator
 */

import { createRNG } from '../utils/RNG.js';
import { seedNoise, fractalNoise2D, normalizedNoise2D } from '../utils/Noise.js';
import DebugLog from '../debug/DebugLog.js';

// ─── World size table ─────────────────────────────────────────────────────────

const WORLD_SIZES = {
  small:  { w: 40,  h: 30  },
  medium: { w: 60,  h: 45  },
  large:  { w: 80,  h: 60  },
  epic:   { w: 120, h: 90  },
};

// ─── Norse name tables ────────────────────────────────────────────────────────

const NAME_PREFIXES = [
  'Vik', 'Heim', 'Fjord', 'Ull', 'Skald', 'Myr', 'Nid', 'Aes',
  'Bjar', 'Tyr', 'Ulf', 'Rag', 'Sigurd', 'Dag', 'Erik', 'Gard',
  'Hal', 'Ing', 'Jarl', 'Knut', 'Leif', 'Mod', 'Orm', 'Ran',
];

const NAME_SUFFIXES = [
  'heim', 'borg', 'dal', 'vik', 'gar', 'fjord', 'mund', 'thor',
  'strand', 'by', 'ness', 'fell', 'holt', 'berg', 'sted', 'mark',
];

const TOWN_PREFIXES = [
  'Aska', 'Brann', 'Dimm', 'Eik', 'Frost', 'Grau', 'Hav', 'Isak',
  'Koldr', 'Ljus', 'Mjol', 'Nord', 'Ord', 'Pyrr', 'Raud', 'Sno',
  'Tind', 'Unn', 'Vest', 'Wyn',
];

const TOWN_SUFFIXES = [
  'stad', 'by', 'havn', 'dorf', 'eld', 'keld', 'lyn', 'skar',
  'torp', 'vad', 'vik', 'wald',
];

const LOCATION_PREFIXES = [
  'Black', 'Bone', 'Broken', 'Crimson', 'Dark', 'Forgotten', 'Grim',
  'Haunted', 'Iron', 'Lost', 'Rotten', 'Shadow', 'Silent', 'Stone', 'Twisted',
];

const LOCATION_SUFFIXES = [
  'Barrow', 'Cave', 'Crypt', 'Den', 'Forge', 'Gate', 'Grave',
  'Hall', 'Keep', 'Lair', 'Mound', 'Pass', 'Peak', 'Ruins', 'Shrine',
  'Spire', 'Temple', 'Tomb', 'Tower', 'Vault',
];

// ─── Helpers ──────────────────────────────────────────────────────────────────

/**
 * Generate a procedural Norse name for a region.
 * @param {object} rng
 * @returns {string}
 */
function proceduralNorseName(rng) {
  return rng.pick(NAME_PREFIXES) + rng.pick(NAME_SUFFIXES);
}

/**
 * Generate a procedural town name.
 * @param {object} rng
 * @returns {string}
 */
function proceduralTownName(rng) {
  return rng.pick(TOWN_PREFIXES) + rng.pick(TOWN_SUFFIXES);
}

/**
 * Generate a procedural location name.
 * @param {object} rng
 * @returns {string}
 */
function proceduralLocationName(rng) {
  return rng.pick(LOCATION_PREFIXES) + ' ' + rng.pick(LOCATION_SUFFIXES);
}

/**
 * Assign levels to regions via BFS outward from the start region.
 * @param {Array} regions
 * @param {number} startId
 * @param {object} adjacency — Map<regionId, Set<regionId>>
 * @param {number} startingLevel
 * @param {object} rng
 */
function assignRegionLevels(regions, startId, adjacency, startingLevel, rng) {
  const levelMap = new Map();
  const queue = [startId];
  levelMap.set(startId, startingLevel);

  while (queue.length > 0) {
    const current = queue.shift();
    const currentLevel = levelMap.get(current);

    const neighbors = adjacency.get(current) ?? new Set();
    for (const neighborId of neighbors) {
      if (!levelMap.has(neighborId)) {
        // Adjacent region is 1-2 levels higher, clamped to 1-10
        const delta = rng.nextInt(1, 2);
        const newLevel = Math.min(10, currentLevel + delta);
        levelMap.set(neighborId, newLevel);
        queue.push(neighborId);
      }
    }
  }

  // Apply computed levels to regions
  for (const region of regions) {
    region.level = levelMap.get(region.id) ?? rng.nextInt(3, 8);
  }
}

/**
 * Get Moore neighborhood (8 adjacent cells) within bounds.
 * @param {number} x
 * @param {number} y
 * @param {number} w
 * @param {number} h
 * @returns {Array<{x,y}>}
 */
function getNeighbors(x, y, w, h) {
  const result = [];
  for (let dy = -1; dy <= 1; dy++) {
    for (let dx = -1; dx <= 1; dx++) {
      if (dx === 0 && dy === 0) continue;
      const nx = x + dx;
      const ny = y + dy;
      if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
        result.push({ x: nx, y: ny });
      }
    }
  }
  return result;
}

/**
 * Get 4-directional (Von Neumann) neighbors within bounds.
 * @param {number} x
 * @param {number} y
 * @param {number} w
 * @param {number} h
 * @returns {Array<{x,y}>}
 */
function get4Neighbors(x, y, w, h) {
  const result = [];
  const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
  for (const [dx, dy] of dirs) {
    const nx = x + dx;
    const ny = y + dy;
    if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
      result.push({ x: nx, y: ny });
    }
  }
  return result;
}

// ─── Main generation pipeline ─────────────────────────────────────────────────

const WorldGenerator = {
  /**
   * Generate a complete world from params.
   * @param {object} params
   * @returns {object} worldData
   */
  generate(params) {
    const {
      seed = Date.now(),
      worldSize = 'medium',
      landSeaRatio = 0.6,
      climate = 'temperate',
      magicDensity = 'medium',
      civDensity = 'medium',
      monsterDensity = 'medium',
      startingRegionLevel = 1,
    } = params;

    const t0 = performance.now();
    DebugLog.info(`[world] WorldGenerator.generate; seed=${seed} size=${worldSize}`);

    const dims = WORLD_SIZES[worldSize] ?? WORLD_SIZES.medium;
    const gridW = dims.w;
    const gridH = dims.h;

    // Seed noise with world seed
    seedNoise(seed);

    const rng = createRNG(seed);
    const nameRng = createRNG(seed ^ 0xABCDEF);
    const townRng = createRNG(seed ^ 0x112233);
    const locationRng = createRNG(seed ^ 0x445566);
    const riverRng = createRNG(seed ^ 0x778899);
    const roadRng = createRNG(seed ^ 0xDEADBEEF);

    // ── Step 1: Heightmap ─────────────────────────────────────────────────────

    const cells = [];
    const heightThreshold = 1.0 - landSeaRatio;

    // Noise scale adjusted by world size for consistent-feeling worlds
    const noiseScale = 0.035 * (60 / gridW);
    const moistureScale = 0.05 * (60 / gridW);
    const moistureOffset = seed * 0.00001;

    for (let y = 0; y < gridH; y++) {
      for (let x = 0; x < gridW; x++) {
        // Use fractal noise mapped to [0,1] for height
        const rawH = fractalNoise2D(x * noiseScale, y * noiseScale, 7, 0.5, 2.0);
        // Normalize from ~[-1,1] to [0,1]
        const height = Math.max(0, Math.min(1, (rawH + 1) * 0.5));

        cells.push({ x, y, height, biome: 'ocean', regionId: -1 });
      }
    }

    // ── Step 2: Biomes ────────────────────────────────────────────────────────

    // Moisture noise for humidity-based biomes
    for (let y = 0; y < gridH; y++) {
      for (let x = 0; x < gridW; x++) {
        const cell = cells[y * gridW + x];
        const height = cell.height;
        const latitude = y / (gridH - 1); // 0 = top (north), 1 = bottom (south)

        const moisture = normalizedNoise2D(
          x * moistureScale + moistureOffset,
          y * moistureScale + moistureOffset * 0.7,
          5, 0.5, 2.0
        );

        let biome;

        if (height <= heightThreshold) {
          // Ocean cell — check latitude
          if (latitude < 0.10 || latitude > 0.90) {
            biome = 'frozen_sea';
          } else {
            biome = 'ocean';
          }
        } else {
          // Land cell
          if (height > 0.82) {
            biome = 'mountain';
          } else if (height > 0.78 && moisture > 0.55) {
            biome = 'volcanic';
          } else if (latitude < 0.15 || latitude > 0.85) {
            // Polar band
            if (climate === 'tropical') {
              biome = 'tundra';
            } else {
              biome = 'tundra';
            }
          } else if (latitude < 0.30 || latitude > 0.70) {
            // Sub-polar — taiga/cold forest
            if (climate === 'harsh') {
              biome = moisture > 0.5 ? 'taiga' : 'tundra';
            } else {
              biome = 'taiga';
            }
          } else if (latitude >= 0.35 && latitude <= 0.65) {
            // Equatorial-ish band
            if (moisture < 0.35) {
              biome = 'desert';
            } else if (moisture > 0.65) {
              biome = climate === 'harsh' ? 'forest' : 'jungle';
            } else {
              biome = 'forest';
            }
          } else {
            // Mid latitudes
            if (moisture > 0.55) {
              biome = 'forest';
            } else {
              biome = 'plains';
            }
          }

          // Climate overrides
          if (climate === 'harsh') {
            if (biome === 'forest' && rng.nextFloat() < 0.3) biome = 'taiga';
            if (biome === 'plains' && rng.nextFloat() < 0.25) biome = 'tundra';
          } else if (climate === 'tropical') {
            if (biome === 'taiga') biome = 'forest';
            if (biome === 'tundra' && height <= 0.82) biome = 'plains';
          }

          // M21: new biome placements
          // swamp — low-elevation coastal areas (near ocean) with high moisture
          if (
            (biome === 'forest' || biome === 'jungle' || biome === 'plains') &&
            moisture > 0.70 &&
            height < heightThreshold + 0.08 &&
            rng.nextFloat() < 0.30
          ) {
            biome = 'swamp';
          }

          // crystal_caves — forms within mountain regions (high elevation + low moisture)
          if (biome === 'mountain' && moisture < 0.40 && rng.nextFloat() < 0.18) {
            biome = 'crystal_caves';
          }

          // cursed_wastes — rare corrupted land, spread randomly (prefer desert/plains at mid-level)
          if (
            (biome === 'desert' || biome === 'plains' || biome === 'tundra') &&
            rng.nextFloat() < 0.06
          ) {
            biome = 'cursed_wastes';
          }
        }

        cell.biome = biome;
      }
    }

    // Mark small land clusters near ocean as archipelago
    for (let y = 0; y < gridH; y++) {
      for (let x = 0; x < gridW; x++) {
        const cell = cells[y * gridW + x];
        if (cell.height <= heightThreshold) continue; // skip ocean

        // Count land neighbors
        const neighbors = getNeighbors(x, y, gridW, gridH);
        const landNeighborCount = neighbors.filter(
          n => cells[n.y * gridW + n.x].height > heightThreshold
        ).length;

        // Also check for proximity to ocean (any neighbor that's ocean)
        const hasOceanNeighbor = neighbors.some(
          n => cells[n.y * gridW + n.x].height <= heightThreshold
        );

        if (hasOceanNeighbor && landNeighborCount <= 3 && rng.nextFloat() < 0.4) {
          cell.biome = 'archipelago';
        }
      }
    }

    // ── Step 3: Voronoi regions ───────────────────────────────────────────────

    const regionCountTable = { small: 20, medium: 28, large: 36, epic: 50 };
    const regionCount = regionCountTable[worldSize] ?? 28;

    // Place Voronoi seed points on land cells
    const landCells = cells.filter(c => c.height > heightThreshold);
    const voronoiSeeds = [];

    if (landCells.length > 0) {
      // Distribute seeds with some jitter using stratified sampling
      const shuffledLand = nameRng.shuffle([...landCells]);
      // Pick seeds spread across the map using stride
      const stride = Math.max(1, Math.floor(shuffledLand.length / regionCount));
      for (let i = 0; i < regionCount && i * stride < shuffledLand.length; i++) {
        voronoiSeeds.push({ x: shuffledLand[i * stride].x, y: shuffledLand[i * stride].y });
      }
    }

    // Add distortion to Voronoi via noise
    const distortionScale = 0.12;

    function distortedDist(cx, cy, sx, sy) {
      const dx = cx - sx;
      const dy = cy - sy;
      // Add slight noise warp to the distance metric for organic boundaries
      const warp = fractalNoise2D(cx * distortionScale, cy * distortionScale, 3, 0.5, 2.0) * 3.0;
      return Math.sqrt(dx * dx + dy * dy) + warp;
    }

    // Assign each land cell to nearest Voronoi seed
    for (const cell of cells) {
      if (cell.height <= heightThreshold) {
        cell.regionId = -1; // ocean
        continue;
      }

      let minDist = Infinity;
      let nearestId = 0;
      for (let i = 0; i < voronoiSeeds.length; i++) {
        const d = distortedDist(cell.x, cell.y, voronoiSeeds[i].x, voronoiSeeds[i].y);
        if (d < minDist) {
          minDist = d;
          nearestId = i;
        }
      }
      cell.regionId = nearestId;
    }

    // Build region objects
    const regions = voronoiSeeds.map((seed, i) => ({
      id: i,
      name: proceduralNorseName(nameRng),
      centerX: seed.x,
      centerY: seed.y,
      biome: 'plains',
      level: 1,
      cells: [],
      towns: [],
      locations: [],
      explored: false,
      isStartRegion: false,
    }));

    // Assign cells to regions and compute dominant biome
    const biomeCounts = regions.map(() => ({}));
    for (const cell of cells) {
      if (cell.regionId >= 0 && cell.regionId < regions.length) {
        regions[cell.regionId].cells.push({ x: cell.x, y: cell.y });
        const b = cell.biome;
        biomeCounts[cell.regionId][b] = (biomeCounts[cell.regionId][b] ?? 0) + 1;
      }
    }

    // Set dominant biome for each region
    for (let i = 0; i < regions.length; i++) {
      const counts = biomeCounts[i];
      let maxCount = 0;
      let dominantBiome = 'plains';
      for (const [biome, count] of Object.entries(counts)) {
        if (count > maxCount && biome !== 'ocean' && biome !== 'frozen_sea') {
          maxCount = count;
          dominantBiome = biome;
        }
      }
      regions[i].biome = dominantBiome;
    }

    // Remove regions with no land cells
    const validRegions = regions.filter(r => r.cells.length > 0);
    // Reindex
    const regionIdRemap = new Map();
    validRegions.forEach((r, newId) => {
      regionIdRemap.set(r.id, newId);
      r.id = newId;
    });
    // Update cell regionIds
    for (const cell of cells) {
      if (cell.regionId >= 0) {
        cell.regionId = regionIdRemap.get(cell.regionId) ?? -1;
      }
    }

    // ── Build region adjacency ────────────────────────────────────────────────

    const adjacency = new Map();
    for (const r of validRegions) adjacency.set(r.id, new Set());

    for (let y = 0; y < gridH; y++) {
      for (let x = 0; x < gridW; x++) {
        const cell = cells[y * gridW + x];
        if (cell.regionId < 0) continue;

        const neighbors = get4Neighbors(x, y, gridW, gridH);
        for (const n of neighbors) {
          const nCell = cells[n.y * gridW + n.x];
          if (nCell.regionId >= 0 && nCell.regionId !== cell.regionId) {
            adjacency.get(cell.regionId)?.add(nCell.regionId);
            adjacency.get(nCell.regionId)?.add(cell.regionId);
          }
        }
      }
    }

    // ── Step 8: Starting region (find center-most low-level land region) ──────

    const centerX = gridW / 2;
    const centerY = gridH / 2;

    let bestStartRegion = validRegions[0];
    let bestDist = Infinity;

    for (const r of validRegions) {
      const dx = r.centerX - centerX;
      const dy = r.centerY - centerY;
      const dist = Math.sqrt(dx * dx + dy * dy);
      // Prefer regions near center that have reasonable cell counts
      if (dist < bestDist && r.cells.length > 3) {
        bestDist = dist;
        bestStartRegion = r;
      }
    }

    bestStartRegion.isStartRegion = true;
    bestStartRegion.explored = true;
    const startRegionId = bestStartRegion.id;

    // ── Assign levels via BFS ─────────────────────────────────────────────────

    assignRegionLevels(validRegions, startRegionId, adjacency, startingRegionLevel, rng.fork());

    // ── Step 4: Rivers ────────────────────────────────────────────────────────

    const riverCountTable = { small: 5, medium: 8, large: 10, epic: 14 };
    const riverCount = riverCountTable[worldSize] ?? 8;

    const rivers = [];

    // Find mountain cells as river sources
    const mountainCells = cells.filter(c => c.biome === 'mountain' || (c.height > 0.75 && c.height <= heightThreshold + 0.4));

    for (let r = 0; r < riverCount; r++) {
      if (mountainCells.length === 0) break;

      const startCell = riverRng.pick(mountainCells);
      if (!startCell) continue;

      const path = [{ x: startCell.x, y: startCell.y }];
      const visited = new Set([`${startCell.x},${startCell.y}`]);
      let current = startCell;

      // Follow height gradient downhill toward ocean (max 100 steps)
      for (let step = 0; step < 100; step++) {
        const neighbors = get4Neighbors(current.x, current.y, gridW, gridH);
        let lowest = null;
        let lowestH = current.height;

        for (const n of neighbors) {
          const nc = cells[n.y * gridW + n.x];
          if (visited.has(`${nc.x},${nc.y}`)) continue;
          if (nc.height < lowestH) {
            lowestH = nc.height;
            lowest = nc;
          }
        }

        if (!lowest) break; // stuck — no lower neighbors

        path.push({ x: lowest.x, y: lowest.y });
        visited.add(`${lowest.x},${lowest.y}`);
        current = lowest;

        // Stop when we reach ocean
        if (lowest.height <= heightThreshold) break;
      }

      if (path.length > 3) {
        rivers.push(path);
      }
    }

    // ── Step 5: Towns ─────────────────────────────────────────────────────────

    const civMultiplier = { low: 0.5, medium: 1.0, high: 1.5 };
    const civMult = civMultiplier[civDensity] ?? 1.0;

    const allTowns = [];
    let townIdCounter = 0;

    for (const region of validRegions) {
      if (region.cells.length === 0) continue;

      const townCountBase = Math.floor(townRng.nextInt(1, 3) * civMult);
      const townCount = Math.max(1, Math.min(3, townCountBase));

      // Pick random cells in the region for towns (not mountain/ocean)
      const suitableCells = region.cells.filter(c => {
        const cell = cells[c.y * gridW + c.x];
        return cell.biome !== 'mountain' && cell.biome !== 'ocean' &&
               cell.biome !== 'frozen_sea' && cell.biome !== 'volcanic';
      });

      if (suitableCells.length === 0) continue;

      const shuffledCells = townRng.shuffle([...suitableCells]);

      for (let t = 0; t < Math.min(townCount, shuffledCells.length); t++) {
        const tc = shuffledCells[t];
        let type;
        if (t === 0 && region.level <= 3) {
          type = 'city';
        } else if (t === 0) {
          type = townRng.nextBool(0.4) ? 'city' : 'village';
        } else {
          type = townRng.nextBool(0.3) ? 'village' : 'outpost';
        }

        const town = {
          id: townIdCounter++,
          name: proceduralTownName(townRng),
          x: tc.x,
          y: tc.y,
          regionId: region.id,
          type,
        };

        allTowns.push(town);
        region.towns.push(town);
      }
    }

    // ── Step 6: Spellroads ────────────────────────────────────────────────────

    // Find hub cities (cities in regions with level <= 4, well-connected)
    const cities = allTowns.filter(t => t.type === 'city');
    const hubCount = Math.min(10, Math.max(6, Math.floor(cities.length * 0.6)));

    // Pick spread-out hub cities
    const hubCities = roadRng.shuffle([...cities]).slice(0, hubCount);

    const spellroads = [];

    // Connect hub cities with curved road segments
    for (let i = 0; i < hubCities.length - 1; i++) {
      const from = hubCities[i];
      const to = hubCities[(i + 1) % hubCities.length];

      const road = buildSpellroad(from, to, gridW, gridH, roadRng);
      if (road.length > 1) {
        spellroads.push(road);
      }
    }

    // Also connect first and last for a loop if enough hubs
    if (hubCities.length >= 4) {
      const road = buildSpellroad(hubCities[hubCities.length - 1], hubCities[0], gridW, gridH, roadRng);
      if (road.length > 1) {
        spellroads.push(road);
      }
    }

    // ── Step 7: Special locations ─────────────────────────────────────────────

    const magicMultiplier = { low: 0.5, medium: 1.0, high: 2.0 };
    const magicMult = magicMultiplier[magicDensity] ?? 1.0;
    const monsterMultiplier = { low: 0.5, medium: 1.0, high: 1.5 };
    const monsterMult = monsterMultiplier[monsterDensity] ?? 1.0;

    const locationTypes = [
      { type: 'dungeon',      weight: monsterMult },
      { type: 'cave',         weight: 1.0 },
      { type: 'ruins',        weight: magicMult },
      { type: 'bandit_camp',  weight: monsterMult },
      { type: 'shrine',       weight: magicMult },
      { type: 'waypoint',     weight: 0.8 },
    ];

    const allLocations = [];
    let locationIdCounter = 0;

    for (const region of validRegions) {
      const locationCountBase = locationRng.nextInt(1, 3);
      const locationCount = Math.round(locationCountBase * ((magicMult + monsterMult) / 2));

      const suitableCells = region.cells.filter(c => {
        const cell = cells[c.y * gridW + c.x];
        return cell.biome !== 'ocean' && cell.biome !== 'frozen_sea';
      });

      if (suitableCells.length === 0) continue;

      const shuffledCells = locationRng.shuffle([...suitableCells]);
      const usedCells = new Set(region.towns.map(t => `${t.x},${t.y}`));

      let placed = 0;
      for (const lc of shuffledCells) {
        if (placed >= locationCount) break;
        if (usedCells.has(`${lc.x},${lc.y}`)) continue;

        const locType = weightedPick(locationTypes, locationRng);

        const loc = {
          id: locationIdCounter++,
          type: locType,
          x: lc.x,
          y: lc.y,
          regionId: region.id,
          name: proceduralLocationName(locationRng),
        };

        allLocations.push(loc);
        region.locations.push(loc);
        usedCells.add(`${lc.x},${lc.y}`);
        placed++;
      }
    }

    const elapsed = (performance.now() - t0).toFixed(1);
    DebugLog.info(
      `[world] WorldGenerator complete; regions=${validRegions.length} towns=${allTowns.length} ` +
      `rivers=${rivers.length} roads=${spellroads.length} locations=${allLocations.length} ` +
      `elapsed=${elapsed}ms`
    );

    return {
      params,
      seed,
      gridW,
      gridH,
      cells,
      regions: validRegions,
      rivers,
      towns: allTowns,
      spellroads,
      locations: allLocations,
      startRegionId,
    };
  },
};

// ─── Spellroad path builder ───────────────────────────────────────────────────

/**
 * Build a gently curved road path between two towns.
 * Returns array of normalized {x, y} coordinates (0..1 space).
 * @param {{x,y}} from
 * @param {{x,y}} to
 * @param {number} gridW
 * @param {number} gridH
 * @param {object} rng
 * @returns {Array<{x,y}>}
 */
function buildSpellroad(from, to, gridW, gridH, rng) {
  const points = [];
  const steps = 20;

  // Random control point offset for a bezier-like curve
  const midX = (from.x + to.x) / 2 + rng.nextInt(-6, 6);
  const midY = (from.y + to.y) / 2 + rng.nextInt(-6, 6);

  for (let i = 0; i <= steps; i++) {
    const t = i / steps;
    // Quadratic bezier
    const bx = (1 - t) * (1 - t) * from.x + 2 * (1 - t) * t * midX + t * t * to.x;
    const by = (1 - t) * (1 - t) * from.y + 2 * (1 - t) * t * midY + t * t * to.y;

    points.push({
      x: bx / gridW,
      y: by / gridH,
    });
  }

  return points;
}

// ─── Weighted random pick ─────────────────────────────────────────────────────

/**
 * Pick a type from a weighted list.
 * @param {Array<{type, weight}>} items
 * @param {object} rng
 * @returns {string}
 */
function weightedPick(items, rng) {
  const totalWeight = items.reduce((sum, item) => sum + item.weight, 0);
  let roll = rng.nextFloat() * totalWeight;
  for (const item of items) {
    roll -= item.weight;
    if (roll <= 0) return item.type;
  }
  return items[items.length - 1].type;
}

export default WorldGenerator;
